def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 11):
            if ratio < j * 0.1:
                if j % 2 == 0:
                    score += (11 - j) * np.log(j + ratio**2)
                else:
                    score += (j + 1) * np.exp(-ratio * j)
            else:
                if j % 3 == 0:
                    score += j * np.sqrt(ratio) * np.sin(ratio * j)
                else:
                    score += j * ratio**(1/j)
        if capacity % 3 == 0:
            score *= 1.15
            if item > capacity / 2:
                score += np.log1p(item) * 2
            else:
                score -= np.sqrt(capacity - item)
        else:
            score *= 0.85
            if item < capacity / 3:
                score += np.tanh(item / capacity) * 5
            else:
                score -= np.log(capacity + 1)
        if score < 0:
            score = abs(score) * 0.5
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority * 20
    return priorities
